// Create one item per sheet name, each carrying the binary file
const binary = $input.first().binary;

const sheetNames = [
  'demand_global',
  'demand_transaction',
  'demand_asset',
  'demand_region',
  'demand_departement',
  'demand_explorer',
  'ranking_global_war',
  'audience'
];

return sheetNames.map(name => ({
  json: { sheetName: name },
  binary: binary
}));

// Group rows by sheetName — each batch of rows belongs to one sheet
// extractFromFile adds sheetName to each row when a specific sheet is requested
const sheets = {};

for (const item of $input.all()) {
  const name = item.json.sheetName ?? 'Unknown';
  if (!sheets[name]) sheets[name] = [];
  // Remove sheetName from row data to keep it clean
  const { sheetName: _ignored, ...rowData } = item.json;
  sheets[name].push(rowData);
}

// Limit to last 100 rows per sheet to avoid GPT-4 token overflow
return Object.entries(sheets).map(([name, rows]) => ({
  json: {
    sheetName: name,
    rowCount: rows.length,
    rows: rows.slice(-100)
  }
}));

// Concatenate all AI outputs into one document
const allOutputs = $input.all()
  .map(item => item.json.output || '')
  .filter(o => o.length > 0)
  .join('\n\n---\n\n');

return [{ json: { output: allOutputs } }];
